def model_partition_strategy(total_data_gb, partition_columns, cardinalities):
    partition_count = 1
    for col_name in partition_columns:
        partition_count *= cardinalities[col_name]
    avg_partition_mb = (total_data_gb * 1024) / partition_count
    assessment = 'optimal' if 128 <= avg_partition_mb <= 1024 else 'too small' if avg_partition_mb < 128 else 'too large'
    print(f'{" / ".join(partition_columns)}: {partition_count:,} partitions, {avg_partition_mb:.0f} MB avg [{assessment}]')

cardinalities = {'country': 4, 'region': 30, 'date': 365}
model_partition_strategy(10_000, ['country', 'date'], cardinalities)
model_partition_strategy(10_000, ['country', 'region', 'date'], cardinalities)
